import{c as a,Q as n,j as t,m as p}from"./chunks/framework.Bhbi9jCp.js";const h=JSON.parse('{"title":"OS 总览与心智","description":"","frontmatter":{},"headers":[],"relativePath":"osLearning/01-OS总览与心智.md","filePath":"osLearning/01-OS总览与心智.md","lastUpdated":1781095972000}'),e={name:"osLearning/01-OS总览与心智.md"};function i(l,s,o,r,c,d){return n(),t("div",null,[...s[0]||(s[0]=[p(`<h1 id="os-总览与心智" tabindex="-1">OS 总览与心智 <a class="header-anchor" href="#os-总览与心智" aria-label="Permalink to &quot;OS 总览与心智&quot;">​</a></h1><p>学操作系统最大的障碍不是&quot;概念多&quot;,是<strong>根本不知道自己为什么要学</strong>——&quot;我写 Java / Python / Go,内核又不用我管,学这个干嘛&quot;。这个想法恰恰是最大的认知陷阱。真相是:你的程序所有&quot;灵异问题&quot;几乎都出在 OS 这一层——为什么 JVM 堆才用 4G 进程却被杀了?为什么 p99 延迟无缘无故抖一下?为什么加了线程反而变慢?这些问题在框架文档里<strong>永远找不到答案</strong>,因为答案在框架底下。这一篇不教任何具体机制,只回答一个问题:<strong>作为程序员,OS 在你眼里到底是什么</strong>。模型建对了,后面 27 篇都是顺水推舟。</p><blockquote><p>一句话先记住:<strong>OS = 硬件的虚拟化器 + 资源的仲裁者 + 抽象的提供商</strong>——它把 CPU 虚拟化成进程、把内存虚拟化成虚拟地址空间、把千奇百怪的硬件虚拟化成文件。<strong>你看到的&quot;很多 CPU、很多内存、很多文件&quot;全是假的,是 OS 在帮你造梦</strong>。而所有性能问题,本质都是&quot;梦做得不够好&quot;的瞬间——缓存没命中、上下文切换太多、缺页打到了磁盘,都是幻觉破灭的那一刻。</p></blockquote><hr><h2 id="一、三个真实事故-不懂-os-的代价" tabindex="-1">一、三个真实事故:不懂 OS 的代价 <a class="header-anchor" href="#一、三个真实事故-不懂-os-的代价" aria-label="Permalink to &quot;一、三个真实事故:不懂 OS 的代价&quot;">​</a></h2><p>先别讲理论,看三个你大概率亲身遇过(或将来一定会遇到)的场景。</p><p><strong>事故 1:Java 服务被莫名其妙杀掉</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>现象:Java 进程被 Linux 杀了(OOM Killer)</span></span>
<span class="line"><span>疑点:JVM 堆只用了 4G,-Xmx 也只设了 4G,服务器有 16G 内存</span></span></code></pre></div><p>不懂 OS 的人会盯着 <code>-Xmx</code> 看一天。懂的人知道:<strong>JVM 堆只是进程内存的一部分</strong>——还有 Native 内存(JNI、Direct Buffer、线程栈、Metaspace、GC 元数据),这些<strong>完全不受 <code>-Xmx</code> 限制</strong>,可能悄悄涨到 10G+,把进程总内存顶爆,触发 OOM Killer。不懂虚拟内存布局,这个问题永远定位不了。</p><p><strong>事故 2:p99 延迟突然抖动</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>现象:平时 p99 = 50ms,偶尔某些请求飙到 500ms</span></span>
<span class="line"><span>疑点:代码没变、DB 不慢、网络正常</span></span></code></pre></div><p>应用层查不出来,因为问题不在应用层。可能是<strong>缺页中断</strong>(某个内存页被换出去了,访问时要从磁盘读回来);可能是 GC 触发 Stop The World;可能是<strong>CPU 调度延迟</strong>(线程被切到别的核,缓存全失效)。三个嫌疑人,全在 OS 层。</p><p><strong>事故 3:加线程反而变慢</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>单线程:1000 QPS</span></span>
<span class="line"><span>2 线程:1800 QPS(还行)</span></span>
<span class="line"><span>4 线程:2200 QPS(开始打折)</span></span>
<span class="line"><span>8 线程:1500 QPS(反而下降?!)</span></span></code></pre></div><p>罪魁祸首叫<strong>伪共享(false sharing)</strong>——多个线程修改同一个 cache line 上的不同变量,触发 CPU 缓存一致性协议(MESI)疯狂同步,<strong>性能比加锁还差</strong>。不懂 cache line,你永远写不出真正高性能的并发代码。</p><p>为什么这三个事故都查到 OS 头上?看一眼你的代码到硬件之间隔了多少层:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>应用层(你的代码)</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>框架(Spring / React / TensorFlow)</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>运行时(JVM / V8 / CPython)</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>系统库(glibc / libstdc++)</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>系统调用(syscall)</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>内核(Linux / Windows / macOS)</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>硬件(CPU / 内存 / 磁盘 / 网卡)</span></span></code></pre></div><p><strong>95% 的性能瓶颈最终都落到 OS 这一层</strong>。框架优化只能解决一部分,真正的极致性能必须往下打——这就是为什么数据库、消息队列、网关这些性能敏感软件全是 C/C++/Rust 写的(贴近 OS),而不是 Java/Python(离 OS 远)。</p><hr><h2 id="二、os-的本质-就干三件事" tabindex="-1">二、OS 的本质:就干三件事 <a class="header-anchor" href="#二、os-的本质-就干三件事" aria-label="Permalink to &quot;二、OS 的本质:就干三件事&quot;">​</a></h2><p>教科书里 OS 的概念能列出几百个,去掉所有花哨的,<strong>OS 就干三件事</strong>。</p><h3 id="_2-1-虚拟化-virtualization-把有限变-无限" tabindex="-1">2.1 虚拟化(Virtualization):把有限变&quot;无限&quot; <a class="header-anchor" href="#_2-1-虚拟化-virtualization-把有限变-无限" aria-label="Permalink to &quot;2.1 虚拟化(Virtualization):把有限变&quot;无限&quot;&quot;">​</a></h3><p>物理资源是有限的、丑陋的;OS 把它们包装成用户感觉无限的、干净的虚拟资源:</p><table tabindex="0"><thead><tr><th>物理资源</th><th>OS 提供的虚拟资源</th></tr></thead><tbody><tr><td>几个 CPU 核</td><td>无限多个&quot;进程&quot;</td></tr><tr><td>几十 GB 物理内存</td><td>每个进程独立的&quot;虚拟地址空间&quot;</td></tr><tr><td>几块硬盘</td><td>一棵&quot;文件树&quot;</td></tr><tr><td>一张网卡</td><td>任意多个&quot;socket&quot;</td></tr></tbody></table><p>你以为你独占 CPU,其实有几百个进程在抢;你以为你分到了 4GB 内存,其实只是拿到了 4GB 虚拟地址(物理页可能一个都没给你)。<strong>这是 OS 给你造的梦</strong>——而且梦造得太好,大多数人一辈子没醒过。</p><h3 id="_2-2-仲裁-arbitration-资源不够时谁先拿" tabindex="-1">2.2 仲裁(Arbitration):资源不够时谁先拿 <a class="header-anchor" href="#_2-2-仲裁-arbitration-资源不够时谁先拿" aria-label="Permalink to &quot;2.2 仲裁(Arbitration):资源不够时谁先拿&quot;">​</a></h3><p>梦再好,资源终归有限,多个进程要抢,得有人裁决:</p><ul><li>CPU 时间 → 调度器</li><li>内存 → 内存分配器 + OOM Killer</li><li>磁盘 IO → IO 调度器</li><li>网络带宽 → 流量控制</li></ul><blockquote><p>&quot;为什么我的程序卡了&quot;——90% 的答案是<strong>仲裁结果不利于你</strong>:别人在抢,你被排在了后面。理解了这一点,你排查卡顿的第一反应就会从&quot;我代码哪里慢&quot;变成&quot;谁在跟我抢&quot;。</p></blockquote><h3 id="_2-3-抽象-abstraction-千差万别的硬件-统一的接口" tabindex="-1">2.3 抽象(Abstraction):千差万别的硬件,统一的接口 <a class="header-anchor" href="#_2-3-抽象-abstraction-千差万别的硬件-统一的接口" aria-label="Permalink to &quot;2.3 抽象(Abstraction):千差万别的硬件,统一的接口&quot;">​</a></h3><p>你写一行 <code>read(fd, buf, 1024)</code>,OS 在底下做的事:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你看到的:</span></span>
<span class="line"><span>   open(&quot;/data/file.txt&quot;)</span></span>
<span class="line"><span>   read(fd, buf, 1024)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>OS 在做的:</span></span>
<span class="line"><span>   判断这是 SSD 还是 HDD 还是 NFS</span></span>
<span class="line"><span>   找到 inode</span></span>
<span class="line"><span>   查页缓存(没命中再发起 IO)</span></span>
<span class="line"><span>   触发 DMA</span></span>
<span class="line"><span>   等中断</span></span>
<span class="line"><span>   把数据拷到你的 buffer</span></span></code></pre></div><p>抽象的好处是你不用管硬件;<strong>抽象的代价是你不知道底下发生了什么</strong>——所以&quot;看起来一样的代码&quot;性能可能差 1000 倍:同样一句 read,从页缓存读和从 NFS 跨网络读,完全是两个世界。</p><hr><h2 id="三、用户态-vs-内核态-os-最重要的一条线" tabindex="-1">三、用户态 vs 内核态:OS 最重要的一条线 <a class="header-anchor" href="#三、用户态-vs-内核态-os-最重要的一条线" aria-label="Permalink to &quot;三、用户态 vs 内核态:OS 最重要的一条线&quot;">​</a></h2><p>OS 把整个世界劈成两半:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─── 用户态 (User Space) ────┐</span></span>
<span class="line"><span>│  你的程序 / JVM / Python    │</span></span>
<span class="line"><span>│  glibc / 标准库              │</span></span>
<span class="line"><span>│  权限低,出错只挂自己         │</span></span>
<span class="line"><span>└──────────────┬─────────────┘</span></span>
<span class="line"><span>               ↓ 系统调用 (syscall)</span></span>
<span class="line"><span>┌──────────────┴─────────────┐</span></span>
<span class="line"><span>│  内核态 (Kernel Space)      │</span></span>
<span class="line"><span>│  调度器 / 内存管理 / 文件系统 │</span></span>
<span class="line"><span>│  网络栈 / 设备驱动           │</span></span>
<span class="line"><span>│  权限高,出错整机崩          │</span></span>
<span class="line"><span>└────────────────────────────┘</span></span></code></pre></div><p>为什么要划这条线?三个理由:</p><ul><li><strong>保护</strong>:用户程序不能直接碰硬件——一个野指针顶多挂掉自己,不能搞挂整个系统</li><li><strong>特权指令</strong>:有些 CPU 指令(改页表、关中断)只有内核能执行</li><li><strong>仲裁需要权威</strong>:多进程共享硬件,仲裁者必须高于所有被仲裁者</li></ul><p>但这条线不是免费的——<strong>跨线很贵</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>普通函数调用:    ~1 ns</span></span>
<span class="line"><span>系统调用:        ~100-1000 ns(慢 100-1000 倍)</span></span>
<span class="line"><span>缺页中断:        ~10 μs</span></span>
<span class="line"><span>进程上下文切换:   ~5 μs</span></span></code></pre></div><p>慢在哪?进出内核要保存/恢复 CPU 状态、切换页表、刷 TLB、污染缓存。<strong>这就是为什么&quot;减少系统调用&quot;是高性能编程的铁律</strong>:用 buffer 攒一批再 write、用 mmap 直接读内存、用 io_uring 批量提交——全是这一个思想的变体(详见 02 篇系统调用、22 篇 io_uring)。</p><p>来看一次最日常的跨线。你写:</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">printf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;hello</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>看起来&quot;打印一行字&quot;,实际发生了:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. printf(用户态 glibc)</span></span>
<span class="line"><span>   攒到 stdout buffer,遇到 \\n 触发 flush</span></span>
<span class="line"><span>2. write(1, &quot;hello\\n&quot;, 6) syscall</span></span>
<span class="line"><span>   陷入 → 切到内核态</span></span>
<span class="line"><span>3. 内核 sys_write</span></span>
<span class="line"><span>   找到 fd 1(标准输出),调用对应文件的 write 操作</span></span>
<span class="line"><span>4. fd 1 是终端 → 走 tty 驱动 → 显存</span></span>
<span class="line"><span>   fd 1 是文件 → 走 ext4 → 写页缓存(异步刷盘)</span></span>
<span class="line"><span>   fd 1 是管道 → 唤醒读端进程</span></span>
<span class="line"><span>5. 返回字节数,切回用户态</span></span></code></pre></div><p><strong>一次 printf 跨了 5 层抽象</strong>——这就是 OS 帮你&quot;藏&quot;起来的复杂度。藏得越好,你越要知道它藏了什么。</p><hr><h2 id="四、三大基本抽象-几乎所有-api-的源头" tabindex="-1">四、三大基本抽象:几乎所有 API 的源头 <a class="header-anchor" href="#四、三大基本抽象-几乎所有-api-的源头" aria-label="Permalink to &quot;四、三大基本抽象:几乎所有 API 的源头&quot;">​</a></h2><p>OS 提供给程序员的&quot;积木&quot;只有三块,<strong>你用过的几乎所有系统 API 都是这三个的变种</strong>。</p><h3 id="_4-1-进程-process-cpu-的虚拟化" tabindex="-1">4.1 进程(Process):CPU 的虚拟化 <a class="header-anchor" href="#_4-1-进程-process-cpu-的虚拟化" aria-label="Permalink to &quot;4.1 进程(Process):CPU 的虚拟化&quot;">​</a></h3><p>&quot;我有自己的 CPU,我的代码在独占地跑&quot;——错觉。实际是多个进程轮流用 CPU:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>进程 A 跑 10ms → 切换 → 进程 B 跑 10ms → 切换 → ...</span></span>
<span class="line"><span>快到你感觉不到,以为各自独占</span></span></code></pre></div><p>详见 11 篇进程。</p><h3 id="_4-2-虚拟内存-virtual-memory-内存的虚拟化" tabindex="-1">4.2 虚拟内存(Virtual Memory):内存的虚拟化 <a class="header-anchor" href="#_4-2-虚拟内存-virtual-memory-内存的虚拟化" aria-label="Permalink to &quot;4.2 虚拟内存(Virtual Memory):内存的虚拟化&quot;">​</a></h3><p>&quot;我有连续的几 GB 甚至几 TB 内存可用&quot;——错觉。实际是页表把虚拟地址映射到物理地址:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>进程 A 的虚拟地址 0x4000_0000 → 物理地址 0x1234_5000</span></span>
<span class="line"><span>进程 B 的虚拟地址 0x4000_0000 → 物理地址 0x9876_F000</span></span>
<span class="line"><span>&quot;同一个地址&quot;,物理上完全不同——所以互不干扰</span></span></code></pre></div><p>详见 06 篇虚拟内存。</p><h3 id="_4-3-文件-file-io-的虚拟化" tabindex="-1">4.3 文件(File):IO 的虚拟化 <a class="header-anchor" href="#_4-3-文件-file-io-的虚拟化" aria-label="Permalink to &quot;4.3 文件(File):IO 的虚拟化&quot;">​</a></h3><p>&quot;一切皆文件&quot;——磁盘、网络、设备、管道、随机数生成器,<strong>全部用 <code>open / read / write / close</code> 这四板斧操作</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fd 0:标准输入(可能是键盘 / 管道 / 文件)</span></span>
<span class="line"><span>fd 1:标准输出(可能是终端 / 管道 / 文件)</span></span>
<span class="line"><span>fd 2:标准错误</span></span>
<span class="line"><span>fd 3+:你 open 的文件 / socket / pipe / ...</span></span></code></pre></div><p>详见 18 篇文件抽象。</p><hr><h2 id="五、os-怎么知道该干活了-中断驱动" tabindex="-1">五、OS 怎么知道该干活了:中断驱动 <a class="header-anchor" href="#五、os-怎么知道该干活了-中断驱动" aria-label="Permalink to &quot;五、OS 怎么知道该干活了:中断驱动&quot;">​</a></h2><p>一个容易建错的模型:&quot;OS 一直在后台跑着,盯着一切&quot;。<strong>错——绝大多数时候 CPU 在跑你的程序,OS 在睡觉</strong>。它不会主动巡逻,被叫醒只有三个原因:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 系统调用(用户主动叫):&quot;我要 read 文件&quot;</span></span>
<span class="line"><span>2. 异常(用户出错):&quot;我访问了非法地址&quot;(SIGSEGV)</span></span>
<span class="line"><span>3. 硬件中断(外部事件):&quot;网卡来了一个包&quot;</span></span></code></pre></div><p>三种事件统称<strong>陷入(trap)</strong>,<strong>OS 是彻头彻尾的事件驱动系统</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户程序跑 → 来个中断 → CPU 切到内核 → 内核处理完 → 切回用户继续跑</span></span></code></pre></div><p>中断的开销决定 OS 的响应延迟——所以高性能场景反而要&quot;避免中断&quot;:DPDK 把网卡驱动搬到用户态绕过内核、轮询模式不等中断持续检查。详见 05 篇中断与异常。</p><hr><h2 id="六、linux-macos-windows-学哪个" tabindex="-1">六、Linux / macOS / Windows:学哪个 <a class="header-anchor" href="#六、linux-macos-windows-学哪个" aria-label="Permalink to &quot;六、Linux / macOS / Windows:学哪个&quot;">​</a></h2><p><strong>90% 的服务器跑 Linux</strong>,所以本系列基本只讲 Linux。三家速览:</p><table tabindex="0"><thead><tr><th>维度</th><th>Linux</th><th>macOS</th><th>Windows</th></tr></thead><tbody><tr><td>内核</td><td>单内核(monolithic)</td><td>混合内核(XNU)</td><td>混合内核(NT)</td></tr><tr><td>用户群</td><td>服务器 / 嵌入式</td><td>个人开发</td><td>个人 / 企业桌面</td></tr><tr><td>进程创建</td><td>fork()</td><td>fork()</td><td>CreateProcess</td></tr><tr><td>多路 IO</td><td>epoll</td><td>kqueue</td><td>IOCP</td></tr><tr><td>系统调用</td><td>syscall(int 0x80 / sysenter)</td><td>syscall</td><td>NT API</td></tr></tbody></table><p>macOS 和 Linux 都是 POSIX 系,<strong>90% 的代码可以跨平台跑</strong>;Windows 是另一个体系。结论:<strong>学 Linux,macOS 顺带就懂,Windows 在服务器场景几乎用不到</strong>。</p><p>本系列的版本基线:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Linux 内核 5.10+(现代发行版默认)</span></span>
<span class="line"><span>glibc 2.31+</span></span>
<span class="line"><span>x86_64 / ARM64</span></span></code></pre></div><p>旧版本(2.6 / 3.x)的特性会单独标注。</p><hr><h2 id="七、看-os-的两种心态" tabindex="-1">七、看 OS 的两种心态 <a class="header-anchor" href="#七、看-os-的两种心态" aria-label="Permalink to &quot;七、看 OS 的两种心态&quot;">​</a></h2><p>学 OS 的人有两种,差别不在&quot;懂多少&quot;,在<strong>心态</strong>:</p><p><strong>A. &quot;OS 是黑盒,我别管&quot;</strong></p><ul><li>出性能问题就&quot;加机器&quot;</li><li>GC 打挂就&quot;换语言&quot;</li><li>见 SIGKILL 就&quot;重启就好&quot;</li><li>永远停在中级工程师</li></ul><p><strong>B. &quot;OS 是工具,我能透视&quot;</strong></p><ul><li>看到 OOM 用 <code>pmap</code> 看真实内存布局</li><li>看到延迟抖动用 <code>perf</code> / <code>bpftrace</code> 找根因</li><li>看到死锁用 <code>gdb</code> 看线程栈</li><li>见 GC 慢能讲清是 STW、page fault 还是 swap</li><li>能成长为架构师 / 系统工程师</li></ul><blockquote><p>转变的关键是<strong>敢看底下</strong>——遇到任何性能问题,第一反应不是问&quot;框架文档怎么说&quot;,而是&quot;OS 这一层发生了什么&quot;。这一篇之后的 27 篇,就是教你怎么看底下。</p></blockquote><hr><h2 id="八、本系列的整体地图" tabindex="-1">八、本系列的整体地图 <a class="header-anchor" href="#八、本系列的整体地图" aria-label="Permalink to &quot;八、本系列的整体地图&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01      总览(这篇)</span></span>
<span class="line"><span>02-05   基础:syscall / 程序生命周期 / CPU / 中断</span></span>
<span class="line"><span>        看完知道&quot;OS 怎么和你的程序握手&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>06-10   内存:虚拟内存 / 布局 / 分配 / 缓存</span></span>
<span class="line"><span>        看完不会再被 OOM 问题问倒</span></span>
<span class="line"><span></span></span>
<span class="line"><span>11-17   并发:进程 / 线程 / IPC / 锁 / 调度 / 协程</span></span>
<span class="line"><span>        **最值钱的一层**,Java / Go / Rust 并发模型全靠它</span></span>
<span class="line"><span></span></span>
<span class="line"><span>18-23   IO:文件 / 文件系统 / IO 模型 / epoll / io_uring</span></span>
<span class="line"><span>        **第二值钱**,所有&quot;性能调优&quot;最后都到这里</span></span>
<span class="line"><span></span></span>
<span class="line"><span>24-28   工程:信号 / 容器 / 性能工具 / eBPF</span></span>
<span class="line"><span>        日常用得到的硬通货</span></span></code></pre></div><p><strong>优先级</strong>:01-05 强烈建议每篇都看,这是地基;06-23 是核心战力(13 篇);24-28 按需。</p><hr><h2 id="九、踩坑提醒-总览版-后面每篇细讲" tabindex="-1">九、踩坑提醒(总览版,后面每篇细讲) <a class="header-anchor" href="#九、踩坑提醒-总览版-后面每篇细讲" aria-label="Permalink to &quot;九、踩坑提醒(总览版,后面每篇细讲)&quot;">​</a></h2><ol><li><strong>以为 OS 不重要</strong>——所有性能瓶颈最后都到这层,框架文档救不了你</li><li><strong>以为 syscall 是免费的</strong>——比函数调用慢 1000 倍,数量决定性能上限</li><li><strong>以为虚拟内存 = 物理内存</strong>——分配 8GB 不代表用了 8GB,但只用 4GB 也可能 OOM</li><li><strong>以为线程越多越快</strong>——上下文切换 / 缓存失效 / 锁竞争,加多必慢</li><li><strong>以为 GC 是 Java 独有的问题</strong>——Go / Python / V8 都有,GC 的本质是 OS 层的内存管理思想</li><li><strong>以为 epoll 自动解决一切</strong>——边缘触发 / 水平触发 / 惊群效应,坑一堆</li><li><strong>以为容器是轻量虚拟机</strong>——本质是 namespace + cgroup,排查方式完全不同</li><li><strong>以为 SIGKILL 能&quot;安全停服务&quot;</strong>——SIGKILL 不能被进程处理,数据可能写一半</li><li><strong>以为内存对齐是过时的优化</strong>——cache line 不对齐,false sharing 让性能差 10 倍</li><li><strong>以为读懂 CSAPP 就懂 OS</strong>——CSAPP 是教学视角,工程视角差很远;两者都要</li></ol><hr><p>下一篇:<code>02-系统调用机制.md</code>,讲清楚一次 <code>read()</code> 从你的代码到内核究竟跨了多少层、为什么 syscall 比函数调用慢 1000 倍、glibc 是什么(它不是内核,但很多人以为它是)、vDSO 怎么把 <code>gettimeofday</code> 优化成纯用户态调用,以及为什么 io_uring 是&quot;减少 syscall 数量&quot;的革命。</p>`,94)])])}const g=a(e,[["render",i]]);export{h as __pageData,g as default};
